import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { misAPI } from '../services/api';
import {
  BarChart, Bar, LineChart, Line, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';

export const MISPage = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (user?.role !== 'manager') {
      navigate('/dashboard');
      return;
    }

    const fetchMISData = async () => {
      try {
        const response = await misAPI.getStats();
        setData(response.data);
      } catch (err) {
        setError('Failed to fetch MIS data');
      } finally {
        setLoading(false);
      }
    };

    fetchMISData();
  }, [user, navigate]);

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  if (loading) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <p className="text-gray-600 text-lg">Loading MIS reports...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="min-h-screen bg-gray-100 flex items-center justify-center">
        <div className="bg-red-100 border border-red-400 text-red-700 p-4 rounded">
          {error}
        </div>
      </div>
    );
  }

  const COLORS = ['#0088FE', '#00C49F', '#FFBB28', '#FF8042', '#8884D8'];

  return (
    <div className="min-h-screen bg-gray-100">
      {/* Header */}
      <header className="bg-white shadow">
        <div className="max-w-7xl mx-auto px-4 py-4 sm:px-6 lg:px-8 flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold text-gray-900">📊 MIS Reports</h1>
            <p className="text-gray-600 mt-1">Performance & Progress Dashboard</p>
          </div>
          <div className="flex gap-4">
            <button
              onClick={() => navigate('/dashboard')}
              className="px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition"
            >
              Back to Dashboard
            </button>
            <button
              onClick={handleLogout}
              className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition"
            >
              Logout
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8">
        {data && (
          <>
            {/* Summary Stats */}
            <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
              <div className="bg-white p-6 rounded-lg shadow">
                <p className="text-gray-600 text-sm font-semibold">Total Tasks</p>
                <p className="text-4xl font-bold text-blue-600 mt-2">{data.summary.totalTasks}</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <p className="text-gray-600 text-sm font-semibold">Completed</p>
                <p className="text-4xl font-bold text-green-600 mt-2">{data.summary.completedTasks}</p>
                <p className="text-sm text-gray-500 mt-1">{data.summary.completionRate}% completion</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <p className="text-gray-600 text-sm font-semibold">Overdue</p>
                <p className="text-4xl font-bold text-red-600 mt-2">{data.summary.overdueTasks}</p>
              </div>
              <div className="bg-white p-6 rounded-lg shadow">
                <p className="text-gray-600 text-sm font-semibold">Upcoming (7 days)</p>
                <p className="text-4xl font-bold text-yellow-600 mt-2">{data.summary.upcomingTasks}</p>
              </div>
            </div>

            {/* Charts Row 1 */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
              {/* Task Status Pie Chart */}
              <div className="bg-white p-6 rounded-lg shadow">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Task Status Distribution</h2>
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={[
                        { name: 'Pending', value: data.summary.pendingTasks },
                        { name: 'In Progress', value: data.summary.inProgressTasks },
                        { name: 'Completed', value: data.summary.completedTasks },
                      ]}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      label={({ name, value }) => `${name}: ${value}`}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                    >
                      <Cell fill="#FFBB28" />
                      <Cell fill="#8884D8" />
                      <Cell fill="#00C49F" />
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>

              {/* Department-wise Tasks */}
              <div className="bg-white p-6 rounded-lg shadow">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Tasks by Department</h2>
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data.departmentStats}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="_id" />
                    <YAxis />
                    <Tooltip />
                    <Legend />
                    <Bar dataKey="total" fill="#8884d8" name="Total" />
                    <Bar dataKey="completed" fill="#00C49F" name="Completed" />
                    <Bar dataKey="pending" fill="#FFBB28" name="Pending" />
                  </BarChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Charts Row 2 */}
            <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
              {/* Priority Distribution */}
              <div className="bg-white p-6 rounded-lg shadow">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Tasks by Priority</h2>
                <ResponsiveContainer width="100%" height={300}>
                  <BarChart data={data.priorityStats}>
                    <CartesianGrid strokeDasharray="3 3" />
                    <XAxis dataKey="_id" />
                    <YAxis />
                    <Tooltip />
                    <Bar dataKey="count" fill="#FF8042" name="Count" />
                  </BarChart>
                </ResponsiveContainer>
              </div>

              {/* Task Completion Status */}
              <div className="bg-white p-6 rounded-lg shadow">
                <h2 className="text-xl font-bold text-gray-800 mb-4">Overall Completion</h2>
                <ResponsiveContainer width="100%" height={300}>
                  <PieChart>
                    <Pie
                      data={[
                        { name: 'Completed', value: data.summary.completedTasks },
                        { name: 'Pending', value: data.summary.totalTasks - data.summary.completedTasks },
                      ]}
                      cx="50%"
                      cy="50%"
                      labelLine={false}
                      label={({ name, percent }) => `${name}: ${(percent * 100).toFixed(0)}%`}
                      outerRadius={80}
                      fill="#8884d8"
                      dataKey="value"
                    >
                      <Cell fill="#00C49F" />
                      <Cell fill="#FF8042" />
                    </Pie>
                    <Tooltip />
                  </PieChart>
                </ResponsiveContainer>
              </div>
            </div>

            {/* Employee Performance Table */}
            <div className="bg-white p-6 rounded-lg shadow">
              <h2 className="text-xl font-bold text-gray-800 mb-4">Employee Performance</h2>
              <div className="overflow-x-auto">
                <table className="w-full">
                  <thead className="bg-gray-100 border-b">
                    <tr>
                      <th className="px-4 py-2 text-left text-sm font-semibold text-gray-700">Employee</th>
                      <th className="px-4 py-2 text-center text-sm font-semibold text-gray-700">Assigned</th>
                      <th className="px-4 py-2 text-center text-sm font-semibold text-gray-700">Completed</th>
                      <th className="px-4 py-2 text-center text-sm font-semibold text-gray-700">Pending</th>
                      <th className="px-4 py-2 text-center text-sm font-semibold text-gray-700">In Progress</th>
                      <th className="px-4 py-2 text-center text-sm font-semibold text-gray-700">Completion Rate</th>
                    </tr>
                  </thead>
                  <tbody>
                    {data.employeePerformance.map((emp, idx) => (
                      <tr key={idx} className="border-b hover:bg-gray-50">
                        <td className="px-4 py-3 text-gray-800 font-semibold">{emp.employeeName}</td>
                        <td className="px-4 py-3 text-center text-gray-600">{emp.totalAssigned}</td>
                        <td className="px-4 py-3 text-center text-green-600 font-semibold">{emp.completed}</td>
                        <td className="px-4 py-3 text-center text-yellow-600 font-semibold">{emp.pending}</td>
                        <td className="px-4 py-3 text-center text-blue-600 font-semibold">{emp.inProgress}</td>
                        <td className="px-4 py-3 text-center">
                          <span className={`px-3 py-1 rounded-full text-sm font-semibold ${
                            emp.completionRate >= 75 ? 'bg-green-100 text-green-800' :
                            emp.completionRate >= 50 ? 'bg-yellow-100 text-yellow-800' :
                            'bg-red-100 text-red-800'
                          }`}>
                            {emp.completionRate}%
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </>
        )}
      </main>
    </div>
  );
};
